import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"57. Sabbatical Leave","description":"","frontmatter":{"title":"57. Sabbatical Leave","eba":"Medical Specialists 2022-2026","topics":["leave","wages","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/57-sabbatical-leave.md","filePath":"ebas/medical-specialists/leave/57-sabbatical-leave.md"}'),i={name:"ebas/medical-specialists/leave/57-sabbatical-leave.md"};function s(n,e,c,l,p,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_57-sabbatical-leave" tabindex="-1">57. Sabbatical Leave <a class="header-anchor" href="#_57-sabbatical-leave" aria-label="Permalink to &quot;57. Sabbatical Leave&quot;">​</a></h1><p>Note: A Doctor’s entitlement under this clause may be affected by <a href="/eba/ebas/medical-specialists/preliminary/7-saving-of-local-agreements.html">clause 7</a> (Savings of Local Agreements).</p><p><strong>57.1</strong> Definitions</p><p>For the purpose of this clause only, the following definitions apply:</p><p><strong>(a)</strong> Salary or Wage means the Doctor’s salary or wage (including allowances) at the time leave is taken;</p><p><strong>(b)</strong> Service means, subject to subclause 57.2(c) of this Agreement, service from the date of first entering employment with the Health Service or Statutory Body (whether or not such Health Service or Statutory Body has been</p><p>transmitted from one Health Service to another during the period such employment), and includes all periods of paid leave including all periods during which the Doctor was serving in Her Majesty’s Forces or was made available by the Health Service or Statutory Body for National Duty</p><p>In calculating such aggregate service:</p><p><strong>(i)</strong> any period of employment in any one Health Service of less than six continuous months’ duration is disregarded.</p><p><strong>(ii)</strong> service is deemed to be unbroken, but not counted towards calculating aggregate service, in respect of any period of absence from employment between an engagement with one Health Service and another of five weeks’ or less (excluding all periods of paid annual leave, long service leave or personal/carer’s leave); and</p><p><strong>(iii)</strong> Service, for the purpose of Sabbatical Leave is where the Doctor has been engaged in medical undergraduate or postgraduate teaching or research with a Health Service throughout that period;</p><p><strong>(c)</strong> Relevant Period for the purpose of Sabbatical Leave means:</p><p><strong>(i)</strong> six years’ continuous Service with one Employer as a Doctor;</p><p><strong>(ii)</strong> six years’ continuous Service across two or more Employers as a Doctor where the Doctor has at least three years’ continuous service with their current Employer;</p><p><strong>(iii)</strong> nine years’ continuous Service across two or more Employers as a Doctor where the Doctor has at least two years’ continuous service with their current Employer; or</p><p><strong>(iv)</strong> twelve years continuous Service across two or more Employers as a Doctor where the Doctor has at least six months’ continuous service with their current Employer;</p><p><strong>(d)</strong> Sabbatical Advisory Committee means a committee whose terms of reference include the function of providing advice in relation to Applications for Sabbatical Leave;</p><p><strong>(e)</strong> Health Service has the same meaning as subclause 3.1(u) of this Agreement;</p><p><strong>(f)</strong> Application for Sabbatical Leave means an application made pursuant to this clause.</p><p><strong>57.2</strong> General Terms</p><p><strong>(a)</strong> Subject to the provisions set out in subclause 57.3 of this Agreement, a Doctor may make an Application for Sabbatical Leave after the completion of the Relevant Period where:</p><p><strong>(i)</strong> the sole purpose of the Sabbatical Leave is to undertake a course of study or research related to his or her work; and</p><p><strong>(ii)</strong> the Doctor has been engaged in medical undergraduate or postgraduate teaching or research with a Health Service throughout that period;</p><p><strong>(b)</strong> Sabbatical Leave may be taken in two periods of up to 13 weeks’ duration which are taken within 2 years of each other.</p><p><strong>(c)</strong> The onus of proving a sufficient aggregate of service to support a claim for sabbatical Leave will rest with the Doctor.</p><p><strong>57.3</strong> Entitlement</p><p><strong>(a)</strong> Service with the same Employer for a period exceeding six years</p><p><strong>(i)</strong> A Doctor who has been in the service of the same Health Service for the Relevant Period specified in subclause 57.1(c)(i) of this Agreement is entitled to a maximum of 26 weeks’ leave of absence on full salary or wages for the purposes of undertaking a period of approved Sabbatical Leave in accordance with this clause.</p><p><strong>(b)</strong> Service across multiple employers for a period exceeding six years</p><p><strong>(i)</strong> A Doctor who is and has been in the service of one or more Health Services (including any Statutory Body directly associated with such Health Service or Health Services) for the Relevant Period specified in subclause 57.1(c)(i) of this Agreement, is entitled to a maximum of 26 weeks’ leave of absence on full salary or wages.</p><p>Example: A Doctor was employed at Hospital A as a Medical Specialist for five years before terminating and immediately commencing a new role at Hospital B as a Medical Specialist.</p><p>The Doctor, upon commencing at Hospital B will be have to complete a further three years’ service before being eligible for Sabbatical Leave.</p><p><strong>(c)</strong> Where Sabbatical Leave is less than 26 weeks duration</p><p><strong>(i)</strong> Subject to subclause 57.357.2(b), where a Doctor proceeds on Sabbatical Leave of less than 26 weeks’ duration, the Doctor will be deemed to have received his/her full entitlement under this clause and he/she will not be entitled to claim an entitlement representing (in part or in whole) the balance of the 26 weeks (if any).</p><p><strong>(ii)</strong> The absence of a Doctor on Sabbatical Leave will be prima facie evidence that he/she has received his/her full entitlement under this clause. Where Sabbatical Leave is taken in two periods of 13 weeks as allowed under subclause 57.2(b), the provisions of this clause will apply to each 13 week period.</p><p><strong>(d)</strong> Calculation of Relevant Period following Sabbatical Leave</p><p><strong>(i)</strong> Where a Doctor has proceeded on Sabbatical Leave, a subsequent Relevant Period as specified in subclause 57.1(c) of this Agreement, will not commence to run until the date of the Doctor’s return to duty following Sabbatical Leave.</p><p><strong>(ii)</strong> Provided that where by mutual agreement a Doctor has delayed the taking of Sabbatical Leave, that period of service between the end of the Relevant Period and the taking of such leave will be included as part of a subsequent Relevant Period.</p><p><strong>57.4</strong> Application for Sabbatical Leave</p><p><strong>(a)</strong> The Doctor’s application for Sabbatical Leave must be in writing and contain:</p><p><strong>(i)</strong> adequate details of the proposed programme of study or research and how it relates to the Doctor’s work; and</p><p><strong>(ii)</strong> details of the Doctor’s engagement in medical undergraduate or postgraduate teaching or research with a Health Service throughout the Relevant Period.</p><p><strong>57.5</strong> Response of the Health Service</p><p><strong>(a)</strong> Where a Doctor has made an Application for Sabbatical Leave in accordance with subclause 57.4, the Employer will, within three months of the written application being received, notify the Doctor in writing whether their Application for Sabbatical Leave has been:</p><p><strong>(i)</strong> approved as requested; or</p><p><strong>(ii)</strong> approved with modifications or conditions; or</p><p><strong>(iii)</strong> refused.</p><p><strong>(b)</strong> Where the Application for Sabbatical Leave has been:</p><p><strong>(i)</strong> approved as requested or</p><p><strong>(ii)</strong> with modifications or conditions that are agreeable to the Doctor,</p><p>the Sabbatical Leave will be given as soon as practicable having regard to the needs of the Health Service, but the taking of such leave may be postponed to a mutually agreed date.</p><p><strong>(c)</strong> Where the Application for Sabbatical Leave has been:</p><p><strong>(i)</strong> approved with modifications or conditions that are not agreeable to the Doctor; or,</p><p><strong>(ii)</strong> refused,</p><p>the Health Service must provide their reasons in writing and the Doctor may request that the Sabbatical Advisory Panel reviews the Application for Sabbatical Leave and the Response of the Health Service and provide advice.</p><p><strong>57.6</strong> Referral to the Sabbatical Advisory Panel</p><p>The Health Service and the Doctor must comply with the written advice of the Sabbatical Advisory Committee except that it may be varied by mutual agreement between the Health Service and the Doctor.</p>',57)])])}const u=t(i,[["render",s]]);export{g as __pageData,u as default};
